        const ctx: Ctx = { req, res: {}, state: {} };
        let index = 0;
        const next = async (): Promise<void> => {
            if (index < this.middlewares.length) {
                await this.middlewares[index++](ctx, next);
            }
        };
        await next();
        return ctx.res;
    }
}

