abstract class BaseBuilder<T> {
    protected data: Partial<T> = {} as Partial<T>;

    set<K extends keyof T>(key: K, value: T[K]): this {
        this.data[key] = value;
        return this;
    }

    abstract build(): T;
}

class UserBuilder extends BaseBuilder<{ name: string; age: number; email: string }> {
    build() {
        if (!this.data.name || !this.data.age || !this.data.email) {
            throw new Error('缺少必填字段');
        }
        return this.data as { name: string; age: number; email: string };
    }
}

